def is_claim_supported(claim):
    """
    Evaluates whether a given claim from Ancient Apocalypse is supported by mainstream archaeology.
    Returns a dictionary with a boolean indicating support and a brief explanation.
    """
    unsupported_claims = [
        "advanced civilization existed during the last ice age",
        "meteor impacts destroyed an advanced civilization 12,000 years ago",
        "survivors of the lost civilization passed knowledge to hunter-gatherers worldwide"
    ]

    claim_lower = claim.lower()

    for unsupported_claim in unsupported_claims:
        if unsupported_claim in claim_lower:
            return {
                "supported": False,
                "reason": "This claim is considered pseudoarchaeological and lacks mainstream archaeological evidence."
            }

    return {
        "supported": True,
        "reason": "The claim aligns with well-established archaeological consensus."
    }

# Example usage:
print(is_claim_supported("Meteor impacts destroyed an advanced civilization 12,000 years ago"))
# Output: {'supported': False, 'reason': 'This claim is considered pseudoarchaeological and lacks mainstream archaeological evidence.'}
